mapper.sql:
WHERE d.merchant_id=#{merchantId}
  AND d.region=#{region}
  AND d.is_deleted=FALSE
AND d.shop_id=#{shopId}

    AND d.shop_id IN
    #{id}

AND d.audit_status=#{auditStatus}
AND d.status=#{status}

mapper.select:
SELECT 
FROM deal d JOIN shop s ON s.id=d.shop_id

ORDER BY d.id DESC LIMIT #{limit} OFFSET #{offset}

mapper.sql:
WHERE s.merchant_id=#{merchantId}
  AND o.region=#{region}
  AND s.region=#{region}
  AND s.is_deleted=FALSE
AND o.shop_id=#{shopId}

    AND o.shop_id IN
    #{id}

AND o.pay_status=#{payStatus}

    AND EXISTS (
        SELECT 1 FROM refund r WHERE r.order_id=o.id AND r.status=#{refundStatus}
    )

AND o.order_no=#{orderNo}
AND o.created_at>=#{dateFrom}
AND o.created_at<#{dateToExclusive}

mapper.select:
SELECT 
FROM `order` o
JOIN deal d ON d.id=o.deal_id
JOIN shop s ON s.id=o.shop_id
WHERE o.id=#{orderId}
  AND s.merchant_id=#{merchantId}
  AND o.region=#{region}
  AND s.region=#{region}
  AND s.is_deleted=FALSE
